What does this program print? Assume no crashes.

```cpp
#include <iostream>
struct Pair {
    int* m_ptr;
    Pair(int v) : m_ptr{new int{v}} {}
    ~Pair() { delete m_ptr; }
    // no custom copy constructor
};
int main() {
    Pair a{10};
    Pair b{a};       // shallow copy
    *b.m_ptr = 99;
    std::cout << *a.m_ptr << '\n';
}
```

